// 맵의 키 목록 추출
func Keys[K comparable, V any](
    m map[K]V) []K {
    keys := make([]K, 0, len(m))
    for k := range m {
        keys = append(keys, k)
    }
    return keys
}

// 슬라이스 필터
func Filter[T any](
    s []T, fn func(T) bool) []T {
    var result []T
    for _, v := range s {
        if fn(v) {
            result = append(result, v)
        }
    }
    return result
}

evens := Filter([]int{1,2,3,4,5},
    func(n int) bool { return n%2 == 0 })
// [2, 4]

